import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"Heatmap","description":"","frontmatter":{},"headers":[],"relativePath":"guide/heatmap.md","filePath":"guide/heatmap.md","lastUpdated":1771855656000}'),n={name:"guide/heatmap.md"};function i(s,e,l,h,p,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="heatmap" tabindex="-1">Heatmap <a class="header-anchor" href="#heatmap" aria-label="Permalink to &quot;Heatmap&quot;">​</a></h1><p>The Heatmap view gives you a bird&#39;s-eye view of your entire lab history in one grid. Instead of reading individual charts, you can scan all your markers across all your dates at a glance.</p><h2 id="what-the-heatmap-shows" tabindex="-1">What the Heatmap Shows <a class="header-anchor" href="#what-the-heatmap-shows" aria-label="Permalink to &quot;What the Heatmap Shows&quot;">​</a></h2><p>Each row in the grid represents one biomarker. Each column represents a lab date. The cell at the intersection is colored by the status of that marker on that date:</p><ul><li><strong>Green</strong> — value is within the normal reference range</li><li><strong>Red</strong> — value is above the upper reference limit (high)</li><li><strong>Blue</strong> — value is below the lower reference limit (low)</li><li><strong>Gray / empty</strong> — no result for that marker on that date</li></ul><h2 id="spotting-patterns" tabindex="-1">Spotting Patterns <a class="header-anchor" href="#spotting-patterns" aria-label="Permalink to &quot;Spotting Patterns&quot;">​</a></h2><p>The heatmap is particularly good for:</p><ul><li><strong>Persistent problems</strong> — A row that stays red or blue across many dates indicates a marker that has been consistently out of range.</li><li><strong>Improvements</strong> — A row that shifts from red to green shows a marker that moved back into range over time.</li><li><strong>Missing data</strong> — Gray cells reveal dates where a particular test was not run, helping you decide what to include in your next lab order.</li><li><strong>Category clusters</strong> — Because markers are grouped by category, you can often see whether a whole metabolic area (e.g., lipids or thyroid) has been in or out of balance.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use the date range filter in the header to narrow the heatmap to a specific period. This is helpful when you have many dates and want to focus on a particular intervention window.</p></div><h2 id="navigating-from-the-heatmap" tabindex="-1">Navigating from the Heatmap <a class="header-anchor" href="#navigating-from-the-heatmap" aria-label="Permalink to &quot;Navigating from the Heatmap&quot;">​</a></h2><p>Click any cell in the heatmap to open the detail modal for that marker, where you can see the exact value, reference range, notes, and an AI interpretation.</p>',11)])])}const u=a(n,[["render",i]]);export{m as __pageData,u as default};
